import { useEffect, useRef, useState } from 'react'
import { useWebSocket } from './hooks/useWebSocket'

type Agent = {
  id: string
  title: string
  department: string
  description: string
  status: 'idle' | 'running' | 'error'
  reports_to?: string
  subordinates?: string[]
  rank?: string
  team?: string
}

type Team = {
  id: string
  name: string
  executive_sponsor: string
  head: string
  members: string[]
}

type Mission = {
  id: string
  title: string
  type: 'engineering' | 'research'
  status: string
  current_stage: string
  assignee: string | null
  workspace: string | null
  sessions: Record<string, string>
  parent_mission?: string
}

type Message = {
  id: string
  from: string
  to: string
  missionId: string
  type: 'escalate' | 'report'
  question: string | null
  context: string | null
  summary: string | null
  artifacts: string[] | null
  status: 'pending' | 'answered' | 'done'
  answer: string | null
  created_at: string
}

type Task = {
  id: string
  title: string
  status: string
  created_at: string
  feedback: Array<{ text: string; at: string }>
  mission_id?: string
  assigned_to?: string
  routing_reasoning?: string
  dispatch_error?: string
}

type Channel = {
  id: string
  name: string
  type: 'org' | 'team' | 'direct'
  messageCount?: number
  lastActivity?: string
  participants?: string[]
}

type ChatMessage = {
  id: string
  channel: string
  from: string
  text: string
  replyTo: string | null
  mentions: string[]
  ts: string
}

type LogLine = {
  id: number
  agentId: string
  missionId: string
  text: string
  kind: 'output' | 'error' | 'system'
}

