                          <span className="font-mono text-[11px] text-[#6c8578]">{msg.missionId}</span>
                        </div>

                        <div className="flex items-center gap-2">
                          <span className="font-mono text-[10.5px] text-[#759083]">{formatMessageTime(msg.created_at)}</span>
                          <span
