    setTaskMissionIds(new Set(detail.missions.map((m: Mission) => m.id)))
  } catch (err) {
    console.error(err)
  } finally {
    setTaskDetailLoading(false)
  }
}

function closeTaskDetail() {
  setSelectedTask(null)
  setTaskDetail(null)
  setTaskMissionIds(new Set())
  setLogFilterAgent(null)
}

